SELECT COUNT(*)
FROM methylation_sites
WHERE gene_id = 1 AND methylation_status = 'methylated';

SELECT gene_id, COUNT(methylation_site_id) AS methylation_site_count
FROM methylation_sites
GROUP BY gene_id;

SELECT COUNT(*) 
FROM methylation_annotation 
WHERE annotation_value = 'unmethylated';

SELECT DISTINCT annotation_value AS gene_name
FROM gene_annotations
WHERE annotation_type = 'gene name' AND annotation_source = 'manual';
